async doGenerate({
  prompt, n, aspectRatio, size, seed, providerOptions,
  headers, abortSignal, files, mask,
}: Parameters<ImageModelV3['doGenerate']>[0]): Promise<...> {
  // 1. Parse provider options with schema
  const replicateOptions = await parseProviderOptions({...});

  // 2. Handle multiple image inputs conditionally
  let imageInputs: Record<string, string> = {};
  if (files != null && files.length > 0) {
    if (this.isFlux2Model) {
      // Flux-2: multiple images as input_image, input_image_2, etc.
      for (let i = 0; i < Math.min(files.length, MAX_FLUX_2_INPUT_IMAGES); i++) {
        const key = i === 0 ? 'input_image' : `input_image_${i + 1}`;
        imageInputs[key] = convertImageModelFileToDataUri(files[i]);
      }
    } else {
      // Others: single image
      imageInputs = { image: convertImageModelFileToDataUri(files[0]) };
    }
  }

  // 3. Build dynamic preference header
  const preferHeader: Record<string, string> =
    maxWaitTimeInSeconds != null
      ? { prefer: `wait=${maxWaitTimeInSeconds}` }
      : { prefer: 'wait' };

  // 4. Post request and download results
  const { value: { output } } = await postJsonToApi({...});
  const images = await Promise.all(
    outputArray.map(async url => {
      const { value: image } = await getFromApi({...});
      return image;
    }),
  );

  return { images, warnings, response };
}
